  ('pukao-1fb53453-moex-00091', 'pukao-1fb53453', 'pukao-1fb53453-moex-113-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '關於訴願期間之敘述，下列何者錯誤？', '["利害關係人知悉一般處分後，如該處分經公告生效已超過3年，不得提起訴願", "訴願人以掛號郵寄方式提起訴願，以交郵當日之郵戳為準", "訴願人委任事務所在臺北市之律師為代理人，向行政院提起訴願，訴願期間之計算不得扣除在途期間", "訴願人因天災而遲誤訴願期間超過1年者，不得向受理訴願機關申請回復原狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00092', 'pukao-1fb53453', 'pukao-1fb53453-moex-113-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '國立大學學生甲對學校所為之記過處分，經依法提出申訴，仍不服申訴評議決定時，應如何救濟？', '["甲得以申訴決定違法或不當且侵害其權益，逕向教育部提起再申訴", "甲得以申訴決定違法且侵害其權利，逕向行政法院提起撤銷訴訟", "甲得以申訴決定違法或不當且侵害其權益，逕向教育部提起訴願", "甲得以申訴決定違法且侵害其權益，以該學校為被告，逕提起國家賠償訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00093', 'pukao-1fb53453', 'pukao-1fb53453-moex-113-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '關於訴願之管轄，下列敘述何者正確？', '["不服鄉公所之行政處分者，向縣政府所屬各級機關提起訴願", "不服縣政府所屬各級機關之行政處分者，向中央主管部、會、行、處、局、署提起訴願", "不服中央各部、會、行、處、局、署所屬機關之行政處分者，向各部、會、行、處、局、署提起訴願", "不服中央各院之行政處分者，向總統府提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00094', 'pukao-1fb53453', 'pukao-1fb53453-moex-113-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '下列公法上爭議何者由行政法院所審理？', '["政黨違憲解散案", "總統彈劾案", "選舉罷免事件", "收容聲請事件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00095', 'pukao-1fb53453', 'pukao-1fb53453-moex-113-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '主管機關命甲自行拆除違建，甲對此處分不服提起訴願，於訴願審議期間，主管機關已將該違建拆除 完畢，若其訴願經駁回，甲仍不服，應提起何種訴訟以為救濟？', '["撤銷訴訟", "課予義務訴訟", "違法確認訴訟", "一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
